function setupEventListeners(){const s=document.getElementById("startBtn"),a=document.getElementById("autoBtn");s.addEventListener("click",()=>{GAME.isLoading||(!GameSystem.state.isGameStarted?GameSystem.startGame():(GameSystem.state.isPaused=!GameSystem.state.isPaused,GameSystem.state.isPaused||GameSystem.gameLoop()))}),a.addEventListener("click",()=>{GAME.isLoading||GameSystem.state.isGameStarted||(GameSystem.state.isAutoMode=!0,GameSystem.startGame())}),document.addEventListener("keydown",e=>{if(!GameSystem.state.isGameStarted||GameSystem.state.isAutoMode)return;switch(e.key){case"ArrowUp":case"w":"down"!==GameSystem.state.direction&&(GameSystem.state.nextDirection="up");break;case"ArrowDown":case"s":"up"!==GameSystem.state.direction&&(GameSystem.state.nextDirection="down");break;case"ArrowLeft":case"a":"right"!==GameSystem.state.direction&&(GameSystem.state.nextDirection="left");break;case"ArrowRight":case"d":"left"!==GameSystem.state.direction&&(GameSystem.state.nextDirection="right")}})}
